SELECT
    (
        SELECT COUNT(ID)
        FROM TBL_POST
    ) TOTAL_POST_COUNT,
    (
        SELECT COUNT(ID) / #{limit}
        FROM TBL_POST
    ) TOTAL_PAGE_COUNT
FROM DUAL

mapper.update:
UPDATE TBL_POST
SET POST_TITLE = #{postTitle}, POST_CONTENT = #{postContent}
WHERE ID = #{id}

UPDATE TBL_POST
SET POST_READ_COUNT = POST_READ_COUNT + 1
WHERE ID = #{id}
